.chunk-preview{font-size:11px;color:#64748b;margin-top:4px;line-height:1.4;max-width:420px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.btn{height:36px;padding:0 14px;border:0;border-radius:8px;background:var(--pri);color:#fff;font:inherit;font-weight:500;cursor:pointer;display:inline-flex;align-items:center;gap:6px}
