#m-view .box{max-width:1180px}
.preview-grid{display:grid;grid-template-columns:minmax(0,1.25fr) minmax(320px,.75fr);gap:16px}
.preview-bar{display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:8px}
.file-preview{height:min(66vh,720px);min-height:420px;border:1px solid var(--bd);border-radius:8px;overflow:hidden;background:#f8fafc}
