.meta-grid{grid-template-columns:1fr 1fr}
@media(max-width:900px){.preview-grid{grid-template-columns:1fr}.file-preview{height:60vh;min-height:320px}.grid2,.meta-grid{grid-template-columns:1fr}}
.modal .hd{padding:16px 20px;border-bottom:1px solid var(--bd);display:flex;align-items:center;gap:12px}
.modal .hd h2{margin:0;font-size:16px;font-weight:600;flex:1}
.modal .bd{padding:20px;overflow-y:auto;flex:1}
.modal .ft{padding:14px 20px;border-top:1px solid var(--bd);display:flex;justify-content:flex-end;gap:8px;background:#f8fafc}
.field{margin-bottom:14px}
.field label{display:block;font-size:12px;font-weight:500;color:var(--muted);margin-bottom:4px}
.field input,.field select,.field textarea{width:100%;padding:8px 10px;border:1px solid var(--bd);border-radius:6px;font:inherit;background:#fff}
.field input:focus,.field select:focus,.field textarea:focus{outline:none;border-color:var(--pri-2);box-shadow:0 0 0 3px #0d948822}
.field .hint{font-size:11px;color:var(--muted);margin-top:3px}
.grid2{display:grid;grid-template-columns:1fr 1fr;gap:14px}
.chunk-list{margin-top:8px;max-height:340px;overflow-y:auto;border:1px solid var(--bd);border-radius:6px}
