.toast.on{opacity:1;transform:translateY(0)}
.toast.err{background:var(--err)}
.toast.ok{background:var(--ok)}
.spin{display:inline-block;width:14px;height:14px;border:2px solid #fff;border-top-color:transparent;border-radius:50%;animation:spin 1s linear infinite}
@keyframes spin{to{transform:rotate(360deg)}}
.loading{padding:40px;text-align:center;color:var(--muted)}
</style>
</head>
<body>
<header>
  <h1>📑 Docs Admin</h1>
  <span class="crumb" id="crumb">Phuket Law Firm • LINE-fed document store</span>
</header>
<div class="wrap">
  <div class="stats" id="stats">
    <div class="stat"><div class="label">Total</div><div class="num" id="stat-total">—</div></div>
    <div class="stat"><div class="label">Ready</div><div class="num ok" id="stat-ready">—</div></div>
    <div class="stat"><div class="label">Pending</div><div class="num warn" id="stat-pending">—</div></div>
    <div class="stat"><div class="label">Failed</div><div class="num err" id="stat-failed">—</div></div>
  </div>
  <div class="toolbar">
    <input class="search" id="q" placeholder="🔍 ค้นหา (Semantic = ค้นในเนื้อหา)">
    <div class="toggle" id="search-mode">
      <button type="button" data-mode="exact" class="on">ตรงตัว</button>
      <button type="button" data-mode="semantic">Semantic</button>
    </div>
    <select id="f-status">
      <option value="">สถานะทั้งหมด</option>
      <option value="ready">ready</option>
      <option value="pending">pending</option>
      <option value="failed">failed</option>
      <option value="processing">processing</option>
    </select>
    <button class="btn ghost" id="btn-refresh">↻ รีเฟรช</button>
  </div>
  <div class="card">
    <table>
      <thead><tr>
        <th style="width:160px">Doc No</th>
        <th>ชื่อไฟล์</th>
        <th style="width:130px">ความเหมือน</th>
        <th>ตัวอย่างที่ match</th>
        <th style="width:120px">Category</th>
        <th style="width:90px">Status</th>
        <th style="width:70px;text-align:right">Chunks</th>
        <th style="width:140px">อัปโหลด</th>
        <th style="width:170px"></th>
      </tr></thead>
      <tbody id="tbody">
        <tr><td colspan="9" class="loading">กำลังโหลด…</td></tr>
      </tbody>
    </table>
  </div>
</div>

<!-- View Modal -->
<div class="modal" id="m-view">
  <div class="box">
    <div class="hd"><h2 id="v-title">รายละเอียดเอกสาร</h2><button class="btn ghost sm" onclick="closeModal('m-view')">✕</button></div>
    <div class="bd" id="v-body"></div>
    <div class="ft"><button class="btn ghost" onclick="closeModal('m-view')">ปิด</button><button class="btn ghost" id="v-open-btn">เปิดไฟล์</button><button class="btn" id="v-edit-btn">แก้ไข</button></div>
  </div>
</div>

<!-- Edit Modal -->
<div class="modal" id="m-edit">
  <div class="box">
    <div class="hd"><h2>แก้ไขเอกสาร</h2><button class="btn ghost sm" onclick="closeModal('m-edit')">✕</button></div>
    <div class="bd">
      <input type="hidden" id="e-id">
      <div class="grid2">
        <div class="field"><label>Doc No</label><input id="e-doc_no" disabled><div class="hint">ไม่สามารถแก้ไขได้</div></div>
        <div class="field"><label>Status</label>
          <select id="e-status"><option value="ready">ready</option><option value="pending">pending</option><option value="failed">failed</option><option value="processing">processing</option></select>
        </div>
      </div>
      <div class="field"><label>ชื่อไฟล์</label><input id="e-file_name"></div>
      <div class="grid2">
        <div class="field"><label>Category</label><input id="e-category" placeholder="เช่น สัญญาเช่า, หนังสือมอบอำนาจ"></div>
        <div class="field"><label>Source</label><input id="e-source" placeholder="เช่น LINE OA, web upload"></div>
      </div>
    </div>
    <div class="ft">
      <button class="btn ghost" onclick="closeModal('m-edit')">ยกเลิก</button>
      <button class="btn" id="e-save">บันทึก</button>
    </div>
  </div>
</div>

<div class="toast" id="toast"></div>

<script>
const BASE = location.origin;
let allRows = [];
let statsCache = null;

function toast(msg, kind=''){
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'toast on ' + kind;
  setTimeout(()=>t.className='toast '+kind, 2200);
}

async function api(path, opts){
  const r = await fetch(BASE + path, opts);
  if (!r.ok) throw new Error('HTTP '+r.status);
  return r.json();
}

function fmtDate(s){
  if(!s) return '—';
  const d = new Date(s);
  return d.toLocaleString('th-TH',{dateStyle:'short',timeStyle:'short'});
}

function esc(s){return String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}

async function loadStats(){
  try{
    const s = await api('/webhook/admin-stats');
    const v = (s && s.data) || s;
    if (typeof v === 'string') { try { v = JSON.parse(v); } catch {} }
    document.getElementById('stat-total').textContent = v.total??0;
    document.getElementById('stat-ready').textContent = v.ready??0;
    document.getElementById('stat-pending').textContent = v.pending??0;
    document.getElementById('stat-failed').textContent = v.failed??0;
  }catch(e){console.warn('stats',e)}
}

async function loadList(){
  const q = document.getElementById('q').value.trim();
  const st = document.getElementById('f-status').value;
  const mode = (document.querySelector('#search-mode button.on')||{}).dataset?.mode || 'exact';
  document.body.dataset.searchMode = mode;
  const params = new URLSearchParams();
  if(q) params.set('q', q);
  if(st) params.set('status', st);
  params.set('limit', '200');
  const url = (mode === 'semantic')
    ? '/webhook/admin-semantic-search?'+params.toString()
    : '/webhook/admin-list?'+params.toString();
  try{
    const data = await api(url);
    allRows = Array.isArray(data)?data:((data&&data.data)||[]);
    render();
  }catch(e){
    document.getElementById('tbody').innerHTML = \`<tr><td colspan="9" class="empty"><h3>โหลดไม่สำเร็จ</h3>\${esc(e.message)}</td></tr>\`;
  }
}

function render(){
  const tb = document.getElementById('tbody');
  const isSem = (document.body.dataset.searchMode === 'semantic');
  if(!allRows.length){
    const msg = isSem ? 'ไม่พบเอกสารที่คล้ายกัน' : 'ไม่มีเอกสาร';
    const hint = isSem ? 'ลองค้นหาด้วยคำอื่น หรือเปลี่ยนเป็นโหมดตรงตัว' : 'อัปโหลดผ่าน LINE OA เพื่อเริ่มต้น';
    tb.innerHTML = \`<tr><td colspan="9" class="empty"><h3>\${esc(msg)}</h3>\${esc(hint)}</td></tr>\`;
    return;
  }
  tb.innerHTML = allRows.map(r=>{
    const simPct = r.similarity != null ? Math.round(parseFloat(r.similarity) * 100) : null;
    const simCell = (isSem && simPct != null) ?
      \`<td><div style="display:flex;align-items:center"><div class="similarity-bar"><span style="width:\${simPct}%"></span></div><span style="font-variant-numeric:tabular-nums;font-size:12px;color:var(--muted)">\${simPct}%</span></div></td>\` :
      \`<td style="color:var(--muted)">—</td>\`;
    const chunkText = (r.top_chunk_content || '').replace(/\s+/g, ' ').slice(0, 120);
    const chunkCell = isSem ?
      \`<td><div class="chunk-preview" title="\${esc((r.top_chunk_content||'').slice(0,300))}">\${esc(chunkText)}</div></td>\` :
      \`<td style="color:var(--muted)">—</td>\`;
    return \`
    <tr>
      <td class="mono">\${esc(r.doc_no||'—')}</td>
      <td><div class="name">\${esc(r.file_name||'')}<small>\${esc(r.file_type||'')}\${r.size_bytes?' • '+Math.round(r.size_bytes/1024)+' KB':''}</small></div></td>
      \${simCell}
      \${chunkCell}
      <td>\${esc(r.category||'—')}</td>
      <td><span class="badge \${esc(r.status||'pending')}">\${esc(r.status||'pending')}</span></td>
      <td style="text-align:right;font-variant-numeric:tabular-nums">\${r.chunk_count??0}</td>
      <td class="mono">\${fmtDate(r.uploaded_at)}</td>
      <td><div class="row-actions">
        <button class="btn ghost sm" onclick="view('\${esc(r.id)}')">ดู</button>
        <button class="btn sm" onclick="edit('\${esc(r.id)}')">แก้ไข</button>
        <button class="btn danger sm" onclick="del('\${esc(r.id)}','\${esc(r.file_name||'')}')">ลบ</button>
      </div></td>
    </tr>
  \`}).join('');
}

async function view(id){
  try{
    const data = await api('/webhook/admin-get?id='+encodeURIComponent(id));
    const r = (Array.isArray(data)?data[0]:((data&&data.data)||data));
    if(!r||!r.id){toast('ไม่พบเอกสาร','err');return}
    const chunks = r.chunks||[];
    const fileUrl = '/webhook/admin-file?id='+encodeURIComponent(id);
    document.getElementById('v-title').textContent = r.file_name||'(ไม่มีชื่อ)';
    document.getElementById('v-body').innerHTML = \`
      <div class="preview-grid">
        <section>
          <div class="preview-bar">
            <div><div class="hint">ไฟล์จาก Postgres</div><strong>\${esc(r.file_name||'document')}</strong></div>
            <a href="\${esc(fileUrl)}" target="_blank" class="btn ghost sm" style="text-decoration:none">เปิดแท็บใหม่</a>
          </div>
          <div class="file-preview"><iframe src="\${esc(fileUrl)}" title="\${esc(r.file_name||'document')}"></iframe></div>
        </section>
        <section>
          <div class="grid2 meta-grid">
            <div><div class="hint">Doc No</div><div class="mono" style="font-weight:500">\${esc(r.doc_no||'—')}</div></div>
            <div><div class="hint">Status</div><span class="badge \${esc(r.status)}">\${esc(r.status)}</span></div>
            <div><div class="hint">Category</div>\${esc(r.category||'—')}</div>
            <div><div class="hint">Source</div>\${esc(r.source||'—')}</div>
            <div><div class="hint">File Type</div>\${esc(r.file_type||'—')}</div>
            <div><div class="hint">Size</div>\${r.size_bytes?(Math.round(r.size_bytes/1024)+' KB'):'—'}</div>
            <div><div class="hint">Line User</div><div class="mono" style="font-size:11px">\${esc(r.line_user_id||'—')}</div></div>
            <div><div class="hint">Line Group</div><div class="mono" style="font-size:11px">\${esc(r.line_group_id||'—')}</div></div>
            <div><div class="hint">อัปโหลด</div>\${fmtDate(r.uploaded_at)}</div>
            <div><div class="hint">อัปเดต</div>\${fmtDate(r.updated_at)}</div>
          </div>
          <div style="margin-top:18px">
            <div class="hint" style="margin-bottom:6px">Chunks (\${chunks.length})</div>
            <div class="chunk-list">\${chunks.length?chunks.map(c=>\`<div class="chunk"><div class="ci">#\${c.chunk_index} • \${c.token_count||0} tokens</div><div class="cp">\${esc(c.preview||'')}</div></div>\`).join(''):'<div class="chunk" style="color:#94a3b8">ยังไม่มี chunks</div>'}</div>
          </div>
        </section>
      </div>
    \`;
    document.getElementById('v-edit-btn').onclick = ()=>{closeModal('m-view');edit(id)};
    document.getElementById('v-open-btn').onclick = ()=>window.open(fileUrl, '_blank');
    document.getElementById('m-view').classList.add('on');
  }catch(e){toast('โหลดรายละเอียดไม่สำเร็จ: '+e.message,'err')}
}

function edit(id){
  const r = allRows.find(x=>x.id===id);
  if(!r){toast('ไม่พบเอกสาร','err');return}
  document.getElementById('e-id').value = id;
  document.getElementById('e-doc_no').value = r.doc_no||'';
  document.getElementById('e-file_name').value = r.file_name||'';
  document.getElementById('e-category').value = r.category||'';
  document.getElementById('e-source').value = r.source||'';
  document.getElementById('e-status').value = r.status||'pending';
  document.getElementById('m-edit').classList.add('on');
}

async function saveEdit(){
  const id = document.getElementById('e-id').value;
  const body = {
    id,
    file_name: document.getElementById('e-file_name').value.trim(),
    category: document.getElementById('e-category').value.trim(),
    source: document.getElementById('e-source').value.trim(),
    status: document.getElementById('e-status').value
  };
  if(!body.file_name){toast('กรุณากรอกชื่อไฟล์','err');return}
  try{
    await api('/webhook/admin-update',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});
    toast('บันทึกเรียบร้อย','ok');
    closeModal('m-edit');
    loadList();loadStats();
  }catch(e){toast('บันทึกไม่สำเร็จ: '+e.message,'err')}
}

async function del(id, name){
  if(!confirm('ลบ "'+name+'"?\\n\\n⚠️ chunks ทั้งหมดจะถูกลบด้วย (CASCADE)')) return;
  try{
    await api('/webhook/admin-delete',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id})});
    toast('ลบเรียบร้อย','ok');
    loadList();loadStats();
  }catch(e){toast('ลบไม่สำเร็จ: '+e.message,'err')}
}

function closeModal(id){document.getElementById(id).classList.remove('on')}

document.getElementById('btn-refresh').onclick = ()=>{loadList();loadStats()};
document.getElementById('q').oninput = debounce(loadList, 300);
document.querySelectorAll('#search-mode button').forEach(btn => {
  btn.onclick = () => {
    document.querySelectorAll('#search-mode button').forEach(b => b.classList.remove('on'));
    btn.classList.add('on');
    loadList();
  };
});
document.getElementById('f-status').onchange = loadList;
document.getElementById('e-save').onclick = saveEdit;

function debounce(fn, ms){let t;return(...a)=>{clearTimeout(t);t=setTimeout(()=>fn(...a),ms)}}

// Read URL query params (?q=, ?status=) and pre-fill inputs
const urlParams = new URLSearchParams(window.location.search);
const urlQ = urlParams.get('q');
const urlStatus = urlParams.get('status');
if (urlQ) document.getElementById('q').value = urlQ;
if (urlStatus) document.getElementById('f-status').value = urlStatus;

loadList();
loadStats();
setInterval(()=>{loadStats()}, 60000);
</script>
</body>
</html>`;
return [{json: {html: html}}];

// Parse json_agg output from PG: Admin List - always exactly 1 row.
const row = $input.first().json;
const data = JSON.parse(row.data_json || '[]');
return [{json: {ok: true, action: 'list', count: row.count, data}}];

// Wrap get result - returns null if no row found
const items = $input.all().map(i => i.json).filter(it => it && it.id != null);
return [{json: {ok: items.length > 0, action: 'get', data: items[0] || null}}];

// Wrap update result
const items = $input.all().map(i => i.json);
return [{json: {ok: true, action: 'update', data: items[0] || null}}];

// Wrap delete result
const items = $input.all().map(i => i.json);
return [{json: {ok: true, action: 'delete', data: items[0] || null}}];

// Wrap stats result - always output 1 item
const items = $input.all().map(i => i.json);
return [{json: {ok: true, action: 'stats', data: items[0] || {total: 0, ready: 0, pending: 0, failed: 0}}}];

// minio_key is computed in SQL (short string, ~26 chars, not ref-compressed).
// Just copy it to _minio_key for MinIO Delete.
const data = $input.first().json;
const minioKey = data.minio_key;
return [{
  json: {
    ...data,
    _minio_bucket: data.storage_bucket,
    _minio_key: minioKey,
    _skip_minio_delete: !minioKey
  }
}];

// Build binary file response from contracts.file_data (Postgres bytea).
const item = $input.first();
const json = item?.json || {};
let mime = json.file_mime || (json.file_type === 'pdf' ? 'application/pdf' : 'application/octet-stream');
let fileName = json.file_name || 'document';
let fileDataB64 = json.file_data_b64 || '';

if (!fileDataB64) {
  const message = 'No file_data stored in Postgres for this document. Re-upload or backfill contracts.file_data.';
  fileDataB64 = Buffer.from(message, 'utf8').toString('base64');
  mime = 'text/plain; charset=utf-8';
  fileName = 'missing-file.txt';
}

const fileSize = Buffer.from(fileDataB64, 'base64').length;
return [{
  json: { file_name: fileName, file_mime: mime, file_size: fileSize },
  binary: {
    data: {
      data: fileDataB64,
      mimeType: mime,
      fileName,
      fileSize,
    }
  }
}];
